\begin{align*}
0.1 + 0.02 + 0.003 + 0.0004 + 0.00005 &= \frac{10000}{100000} + \frac{2000}{100000} + \frac{300}{100000} + \frac{40}{100000} + \frac{5}{100000} \\
&= \frac{12345}{100000}
\end{align*}
